  MINUMAN = 'Minuman',
  SNACK = 'Snack',
  SEMBAKO = 'Sembako',
  ELEKTRONIK = 'Elektronik',
  FASHION = 'Fashion'
}

export enum PaymentMethod {
  CASH = 'Tunai',
  COD = 'COD',
  EWALLET_DANA = 'DANA',
  EWALLET_OVO = 'OVO',
  EWALLET_GOPAY = 'GOPAY',
  EWALLET_SHOPEEPAY = 'ShopeePay',
