  const [selectedCategory, setSelectedCategory] = useState<string>('All');
  const [cart, setCart] = useState<CartItem[]>([]);
  const [discount, setDiscount] = useState(0);
  const [showReceipt, setShowReceipt] = useState(false);
  const [lastTransaction, setLastTransaction] = useState<Transaction | null>(null);
  const [paymentMethod, setPaymentMethod] = useState<PaymentMethod>(PaymentMethod.CASH);

  const categories = ['All', ...Object.values(Category)];

  const filteredProducts = useMemo(() => {
    return products.filter(p => {
      const matchesSearch = p.name.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesCategory = selectedCategory === 'All' || p.category === selectedCategory;
      return matchesSearch && matchesCategory && p.stock > 0;
    });
  }, [products, searchTerm, selectedCategory]);

  const addToCart = (product: any) => {
    const existing = cart.find(item => item.id === product.id);
    if (existing) {
      if (existing.quantity >= product.stock) return;
      setCart(cart.map(item => item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item));
    } else {
      setCart([...cart, { ...product, quantity: 1 }]);
    }
  };

  const removeFromCart = (id: string) => {
    setCart(cart.filter(item => item.id !== id));
  };

  const updateQuantity = (id: string, delta: number) => {
    setCart(cart.map(item => {
      if (item.id === id) {
        const newQty = Math.max(1, item.quantity + delta);
        const originalProduct = products.find(p => p.id === id);
        if (originalProduct && newQty > originalProduct.stock) return item;
        return { ...item, quantity: newQty };
      }
      return item;
    }));
  };

  const subtotal = cart.reduce((sum, item) => sum + (item.price * item.quantity), 0);
  const tax = subtotal * TAX_RATE;
  const total = subtotal + tax - discount;

  const handleCheckout = () => {
    if (cart.length === 0) return;

    const transaction: Transaction = {
      id: `TRX-${Date.now()}`,
      items: [...cart],
      subtotal,
      tax,
      discount,
      total,
      paymentMethod,
      cashierName: user?.name || 'Unknown',
      createdAt: new Date().toISOString(),
    };

    addTransaction(transaction);
    setLastTransaction(transaction);
    setShowReceipt(true);
    setCart([]);
    setDiscount(0);
  };

  const ReceiptModal = () => (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm p-4">
      <div className="bg-white rounded-3xl w-full max-w-md overflow-hidden animate-in zoom-in duration-300">
        <div className="bg-blue-900 p-6 text-white text-center relative">
          <button onClick={() => setShowReceipt(false)} className="absolute right-6 top-6 hover:rotate-90 transition-transform">
            <X size={24} />
          </button>
          <div className="w-16 h-16 bg-white/20 rounded-2xl mx-auto flex items-center justify-center mb-4 border border-white/30">
            <CheckCircle2 size={32} />
          </div>
          <h2 className="text-2xl font-bold">Payment Successful!</h2>
          <p className="text-blue-200 text-sm mt-1">Transaction #{lastTransaction?.id.slice(-6)}</p>
        </div>

        <div className="p-8 space-y-6 receipt-container">
          <div className="text-center border-b border-dashed border-slate-200 pb-6">
            <h3 className="font-black text-xl text-slate-800">MUNIR OFFICIAL</h3>
            <p className="text-xs text-slate-500 font-bold uppercase tracking-widest mt-1">Premium Quality Store</p>
            <p className="text-[10px] text-slate-400 mt-2">{new Date(lastTransaction?.createdAt || '').toLocaleString()}</p>
          </div>

          <div className="space-y-3">
            {lastTransaction?.items.map(item => (
              <div key={item.id} className="flex justify-between items-start">
                <div className="flex items-center space-x-3">
                  <img src={item.image} className="w-8 h-8 rounded object-cover" alt="" />
                  <div>
                    <p className="text-sm font-bold text-slate-800">{item.name}</p>
                    <p className="text-[10px] text-slate-400">{item.quantity} x Rp {item.price.toLocaleString()}</p>
                  </div>
                </div>
                <p className="text-sm font-bold text-slate-700">Rp {(item.price * item.quantity).toLocaleString()}</p>
              </div>
            ))}
          </div>

          <div className="space-y-2 pt-6 border-t border-dashed border-slate-200">
            <div className="flex justify-between text-sm">
              <span className="text-slate-500 font-medium">Subtotal</span>
              <span className="text-slate-700 font-bold">Rp {lastTransaction?.subtotal.toLocaleString()}</span>
            </div>
            <div className="flex justify-between text-sm">
              <span className="text-slate-500 font-medium">Tax (11%)</span>
              <span className="text-slate-700 font-bold">Rp {lastTransaction?.tax.toLocaleString()}</span>
            </div>
            {lastTransaction?.discount ? (
              <div className="flex justify-between text-sm">
                <span className="text-slate-500 font-medium">Discount</span>
                <span className="text-red-500 font-bold">-Rp {lastTransaction.discount.toLocaleString()}</span>
              </div>
            ) : null}
            <div className="flex justify-between text-xl pt-4">
              <span className="font-black text-slate-800">Total</span>
              <span className="font-black text-blue-900">Rp {lastTransaction?.total.toLocaleString()}</span>
            </div>
          </div>

          <div className="pt-6 text-center text-[10px] text-slate-400 uppercase tracking-[0.2em] font-bold">
            Cashier: {lastTransaction?.cashierName} <br/>
            Method: {lastTransaction?.paymentMethod}
          </div>
        </div>

        <div className="p-6 bg-slate-50 flex space-x-4">
          <button 
            onClick={() => window.print()}
            className="flex-1 bg-white border border-slate-200 py-3 rounded-2xl font-bold text-slate-700 hover:bg-slate-100 transition-colors flex items-center justify-center space-x-2"
          >
            <Printer size={18} />
            <span>Print</span>
          </button>
          <button 
            onClick={() => setShowReceipt(false)}
            className="flex-1 luxury-gradient text-white py-3 rounded-2xl font-bold flex items-center justify-center space-x-2 shadow-lg"
          >
            <Download size={18} />
            <span>E-Receipt</span>
          </button>
        </div>
      </div>
    </div>
  );

  return (
    <div className="flex gap-8 h-[calc(100vh-140px)]">
      {showReceipt && <ReceiptModal />}

      {/* Product Selection */}
      <div className="flex-1 flex flex-col space-y-6">
        <div className="flex flex-col space-y-4 md:flex-row md:items-center md:justify-between md:space-y-0">
          <div className="relative w-full max-w-md">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={20} />
            <input 
              type="text" 
              placeholder="Quick search products..." 
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full bg-white border border-slate-200 rounded-2xl py-3 pl-12 pr-4 outline-none focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 transition-all shadow-sm font-medium"
            />
          </div>

          <div className="flex items-center space-x-2 overflow-x-auto pb-2 scrollbar-hide">
            {categories.map(cat => (
              <button
                key={cat}
                onClick={() => setSelectedCategory(cat)}
                className={`px-5 py-2.5 rounded-xl text-sm font-bold whitespace-nowrap transition-all border ${
                  selectedCategory === cat 
                  ? 'bg-blue-900 text-white border-blue-900 shadow-lg' 
                  : 'bg-white text-slate-500 border-slate-100 hover:border-blue-200 hover:text-blue-600'
                }`}
              >
                {cat}
              </button>
            ))}
          </div>
        </div>

        <div className="flex-1 overflow-y-auto pr-2 grid grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
          {filteredProducts.map(product => (
            <div 
              key={product.id} 
              onClick={() => addToCart(product)}
              className="bg-white rounded-3xl p-3 luxury-card border border-slate-100 cursor-pointer group relative overflow-hidden"
            >
              <div className="aspect-square rounded-2xl overflow-hidden mb-3 relative">
                <img 
                  src={product.image} 
                  alt={product.name} 
                  className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-500" 
                />
                <div className="absolute top-2 right-2 bg-white/90 backdrop-blur px-3 py-1 rounded-full text-[10px] font-black text-blue-900 shadow-sm border border-blue-100">
                  Stock: {product.stock}
