import React, { useState, useContext, useMemo } from 'react';
import { StoreContext, AuthContext } from '../App';
import { TAX_RATE } from '../constants';
import { Category, CartItem, Transaction, PaymentMethod } from '../types';
import { 
  Search, Plus, Minus, Trash2, CreditCard, 
  Wallet, Banknote, QrCode, Download, Printer,
  X, CheckCircle2, ChevronRight,
  // Fix: Added missing ShoppingCart import
  ShoppingCart
} from 'lucide-react';

const POS: React.FC = () => {
  const { products, addTransaction } = useContext(StoreContext);
